### Render Recharts Treemap with Custom Content in React

Source: https://context7.com/recharts/recharts/llms.txt

This React component illustrates how to create a Treemap using Recharts to visualize hierarchical data. It defines a custom content component (`CustomizedContent`) to render individual treemap cells with text labels and applies different colors based on their index. The `ResponsiveContainer` ensures the chart adapts to its parent's size.

```jsx
import React from 'react';
import { Treemap, ResponsiveContainer, Tooltip } from 'recharts';

const data = [
  {
    name: 'Products',
    children: [
      {
        name: 'Electronics',
        size: 5000,
        children: [
          { name: 'Phones', size: 2000 },
          { name: 'Laptops', size: 2500 },
          { name: 'Tablets', size: 500 }
        ]
      },
      {
        name: 'Clothing',
        size: 3000,
        children: [
          { name: 'Shirts', size: 1200 },
          { name: 'Pants', size: 1000 },
          { name: 'Shoes', size: 800 }
        ]
      },
      {
        name: 'Food',
        size: 2000,
        children: [
          { name: 'Fruits', size: 800 },
          { name: 'Vegetables', size: 700 },
          { name: 'Dairy', size: 500 }
        ]
      }
    ]
  }
];

const COLORS = ['#8889DD', '#9597E4', '#8DC77B', '#A5D297', '#E2CF45', '#F8C12D'];

const CustomizedContent = (props) => {
  const { x, y, width, height, index, name, value } = props;

  return (
    <g>
      <rect
        x={x}
        y={y}
        width={width}
        height={height}
        style={{
          fill: COLORS[index % COLORS.length],
          stroke: '#fff',
          strokeWidth: 2
        }}
      />
      {width > 50 && height > 30 && (
        <text
          x={x + width / 2}
          y={y + height / 2}
          textAnchor="middle"
          fill="#fff"
          fontSize={14}
        >
          {name}
        </text>
      )}
      {width > 50 && height > 50 && (
        <text
          x={x + width / 2}
          y={y + height / 2 + 20}
          textAnchor="middle"
          fill="#fff"
          fontSize={12}
        >
          {value}
        </text>
      )}
    </g>
  );
};

function TreemapExample() {
  return (
    <ResponsiveContainer width="100%" height={400}>
      <Treemap
        data={data}
        dataKey="size"
        ratio={4 / 3}
        stroke="#fff"
        fill="#8884d8"
        content={<CustomizedContent />}
      >
        <Tooltip />
      </Treemap>
    </ResponsiveContainer>
  );
}

export default TreemapExample;
```

